from dataclasses import dataclass, field
from enum import Enum


class RiskRating(str, Enum):
    LOW = "Low"
    MEDIUM = "Medium"
    HIGH = "High"
    CRITICAL = "Critical"


@dataclass
class VendorInherentRisk:
    """Inherent risk factors — score each 1 (low) to 5 (high)."""
    data_sensitivity: int       # 5 = PII/PHI/financial data
    decision_criticality: int   # 5 = agent powers consequential decisions (credit, medical)
    transaction_volume: int     # 5 = millions of requests/day
    replaceability: int         # 5 = no viable substitute in <90 days

    @property
    def score(self) -> float:
        weights = {"data_sensitivity": 0.35, "decision_criticality": 0.30,
                   "transaction_volume": 0.15, "replaceability": 0.20}
        return sum(getattr(self, k) * w for k, w in weights.items())


@dataclass
class ControlEffectiveness:
    """Control effectiveness — each 0 (absent) to 5 (strong)."""
    soc2_opinion_quality: int       # 5 = unqualified with no exceptions
    questionnaire_completeness: int  # 5 = fully responsive, evidence provided
    incident_history: int            # 5 = no material incidents in 3 years
    financial_stability: int         # 5 = public company or well-funded
    model_change_controls: int       # 5 = 30-day notice + version pinning

    @property
    def score(self) -> float:
        weights = {"soc2_opinion_quality": 0.25, "questionnaire_completeness": 0.20,
                   "incident_history": 0.25, "financial_stability": 0.15,
                   "model_change_controls": 0.15}
        return sum(getattr(self, k) * w for k, w in weights.items())


@dataclass
class ConcentrationRisk:
    """Concentration risk — percentage-based."""
    workload_pct_on_vendor: float   # 0.0 to 1.0
    switching_cost_estimate: int    # 1 (trivial) to 5 (prohibitive)
    has_fallback: bool

    @property
    def score(self) -> float:
        fallback_penalty = 0 if self.has_fallback else 1.5
        return (self.workload_pct_on_vendor * 3 +
                self.switching_cost_estimate * 0.4 +
                fallback_penalty)


def compute_residual_risk(
    inherent: VendorInherentRisk,
    controls: ControlEffectiveness,
    concentration: ConcentrationRisk,
) -> dict:
    inherent_score = inherent.score          # 1–5
    control_factor = 1 - (controls.score / 5) * 0.6   # controls reduce inherent by up to 60%
    conc_factor = 1 + concentration.score * 0.1

    residual = inherent_score * control_factor * conc_factor

    if residual >= 4.0:
        rating = RiskRating.CRITICAL
    elif residual >= 3.0:
        rating = RiskRating.HIGH
    elif residual >= 2.0:
        rating = RiskRating.MEDIUM
    else:
        rating = RiskRating.LOW

    return {
        "inherent_score": round(inherent_score, 2),
        "control_effectiveness": round(controls.score, 2),
        "concentration_score": round(concentration.score, 2),
        "residual_score": round(residual, 2),
        "rating": rating,
        "tier": "Tier 1" if rating in (RiskRating.CRITICAL, RiskRating.HIGH) else
                "Tier 2" if rating == RiskRating.MEDIUM else "Tier 3",
    }


if __name__ == "__main__":
    import json
    # Example: assessing a primary LLM API provider
    result = compute_residual_risk(
        inherent=VendorInherentRisk(
            data_sensitivity=4, decision_criticality=4,
            transaction_volume=3, replaceability=4
        ),
        controls=ControlEffectiveness(
            soc2_opinion_quality=4, questionnaire_completeness=3,
            incident_history=4, financial_stability=5,
            model_change_controls=3
        ),
        concentration=ConcentrationRisk(
            workload_pct_on_vendor=0.75,
            switching_cost_estimate=4,
            has_fallback=False
        ),
    )
    print(json.dumps(result, indent=2, default=str))
